const cockpitCss = ":root[data-theme=\"dark\"] {\n  --bg:#060b18; --panel:#0d1b2a; --card:#112240; --card-2:#153258;\n  --border:#1a3a5c; --border-subtle:#142d4a;\n  --text:#e0f7fa; --muted:#5d9bb8;\n  --accent:#00f0ff; --accent-active:#00e5ff; --accent-secondary:#00b8d4;\n  --accent-subtle:rgba(0,240,255,0.08); --accent-border:rgba(0,240,255,0.25);\n  --status-running:#00f0ff; --status-idle:#5d9bb8; --status-blocked:#ff6b35;\n  --status-done:#64ffda; --status-offline:#4a5666;\n  --health-down:#ff5252; --health-down-soft:rgba(255,82,82,0.08);\n  --glow-card:0 0 1px rgba(0,240,255,0.08);\n  --glow-hover:0 0 8px rgba(0,240,255,0.30);\n  --focus-ring-glow:0 0 0 3px rgba(0,240,255,0.10), 0 0 8px rgba(0,240,255,0.30);\n  --grid-line:rgba(0,240,255,0.025); --hud-mark:rgba(0,240,255,0.32);\n}\n:root[data-theme=\"light\"] {\n  --bg:#eef1f5; --panel:#e8ecf2; --card:#f4f6f9; --card-2:#e0e4ea;\n  --border:#c4cdd8; --border-subtle:#d4dbe4;\n  --text:#0a1628; --muted:#5a6a7e;\n  --accent:#0097a7; --accent-active:#00838f; --accent-secondary:#00bcd4;\n  --accent-subtle:rgba(0,151,167,0.08); --accent-border:rgba(0,151,167,0.25);\n  --status-running:#0097a7; --status-idle:#5a6a7e; --status-blocked:#c45000;\n  --status-done:#2e7d52; --status-offline:#98a4b3;\n  --health-down:#c4001f; --health-down-soft:rgba(196,0,31,0.10);\n  --glow-card:0 1px 2px rgba(10,22,40,0.06);\n  --glow-hover:0 0 6px rgba(0,151,167,0.25);\n  --focus-ring-glow:0 0 0 3px rgba(0,151,167,0.14), 0 0 6px rgba(0,151,167,0.45);\n  --grid-line:rgba(10,22,40,0.04); --hud-mark:rgba(0,151,167,0.45);\n}\n\n*,*::before,*::after { box-sizing:border-box; margin:0; padding:0; }\nhtml,body { height:100%; }\nbody {\n  background:var(--bg); color:var(--text);\n  font-family:'Geist',system-ui,sans-serif;\n  -webkit-font-smoothing:antialiased; text-rendering:optimizeLegibility;\n  transition:background-color 180ms ease, color 180ms ease;\n  min-height:100vh; position:relative; overflow-x:hidden;\n}\nbody::before {\n  content:\"\"; position:fixed; inset:0;\n  background-image:\n    linear-gradient(to right, var(--grid-line) 1px, transparent 1px),\n    linear-gradient(to bottom, var(--grid-line) 1px, transparent 1px);\n  background-size:64px 64px; pointer-events:none; z-index:0;\n}\nbody::after {\n  content:\"\"; position:fixed; inset:0;\n  background:\n    radial-gradient(ellipse at 18% -10%, rgba(0,240,255,0.05), transparent 55%),\n    radial-gradient(ellipse at 100% 110%, rgba(0,184,212,0.04), transparent 55%);\n  pointer-events:none; z-index:0;\n}\n:root[data-theme=\"light\"] body::after { display:none; }\n\n.mono { font-family:'JetBrains Mono',ui-monospace,monospace; font-feature-settings:'zero','ss02'; }\n.num { font-variant-numeric:tabular-nums; }\nbutton, input { font-family:inherit; }\n\n/* ============ FOCUS RING — UNIFIED ============ */\n:root[data-theme=\"dark\"], :root[data-theme=\"light\"] {\n  --focus-color:var(--accent);\n}\n*:focus { outline:none; }\n*:focus-visible {\n  outline:1px solid var(--focus-color);\n  outline-offset:2px;\n  box-shadow:var(--focus-ring-glow);\n  border-radius:1px;\n  z-index:6;\n  position:relative;\n}\n/* certain elements need offset adjustments to look right */\n.agent-card:focus-visible { outline-offset:3px; }\n.kcol:focus-visible { outline-offset:-2px; }\n.krow:focus-visible { outline-offset:-1px; }\n.fb-search input:focus-visible { outline-offset:4px; box-shadow:none; }\n.fb-search:has(input:focus-visible) { box-shadow:var(--focus-ring-glow); outline:1px solid var(--focus-color); outline-offset:0; }\n\n/* ============ CORNER MARKS ============ */\n.corner-mark { position:fixed; width:18px; height:18px; border-color:var(--hud-mark); z-index:8; pointer-events:none; }\n.corner-mark.tl { top:10px; left:10px; border-top:1px solid; border-left:1px solid; }\n.corner-mark.tr { top:10px; right:10px; border-top:1px solid; border-right:1px solid; }\n.corner-mark.bl { bottom:10px; left:10px; border-bottom:1px solid; border-left:1px solid; }\n.corner-mark.br { bottom:10px; right:10px; border-bottom:1px solid; border-right:1px solid; }\n\n.viewport {\n  position:relative; z-index:1; min-height:100vh;\n  padding:20px 28px 0;\n  display:flex; flex-direction:column; gap:18px;\n  transition:padding-top 220ms cubic-bezier(.2,.7,.2,1);\n}\nbody[data-sse=\"off\"] .viewport { padding-top:62px; }\n\n/* ============ SSE BANNER ============ */\n.sse-banner {\n  position:fixed; top:-64px; left:0; right:0; z-index:80;\n  display:flex; align-items:center; gap:0;\n  background:var(--health-down-soft);\n  border-bottom:1px solid var(--health-down);\n  font-family:'JetBrains Mono',monospace; font-size:11px;\n  color:var(--text);\n  opacity:0;\n  transition:top 220ms cubic-bezier(.2,.7,.2,1), opacity 200ms ease;\n  backdrop-filter:blur(6px); -webkit-backdrop-filter:blur(6px);\n  pointer-events:none;\n}\n.sse-banner[data-on=\"true\"] { top:0; opacity:1; pointer-events:auto; }\n.sse-banner .sb-icon {\n  display:flex; align-items:center; justify-content:center;\n  padding:0 16px; height:42px;\n  color:var(--health-down);\n  border-right:1px solid rgba(255,82,82,0.30);\n}\n.sse-banner .sb-icon svg {\n  width:16px; height:16px; stroke:currentColor; fill:none;\n  stroke-width:1.6; stroke-linecap:round; stroke-linejoin:round;\n  animation:icon-blink 1.6s steps(2) infinite;\n}\n:root[data-theme=\"light\"] .sse-banner .sb-icon { border-right-color:rgba(196,0,31,0.30); }\n.sse-banner .sb-msg {\n  display:flex; align-items:center; gap:14px;\n  padding:0 18px;\n  letter-spacing:0.14em; text-transform:uppercase;\n}\n.sse-banner .sb-msg .strong { color:var(--health-down); font-weight:600; }\n.sse-banner .sb-msg .em { color:var(--muted); letter-spacing:0.08em; }\n.sse-banner .sb-msg .attempt {\n  color:var(--health-down);\n  border:1px solid rgba(255,82,82,0.35);\n  padding:2px 8px; font-size:10px; letter-spacing:0.18em;\n}\n:root[data-theme=\"light\"] .sse-banner .sb-msg .attempt { border-color:rgba(196,0,31,0.45); }\n.sse-banner .sep { width:1px; align-self:stretch; background:rgba(255,82,82,0.20); }\n:root[data-theme=\"light\"] .sse-banner .sep { background:rgba(196,0,31,0.30); }\n.sse-banner .sb-stat {\n  display:flex; align-items:center; gap:8px;\n  padding:0 16px; color:var(--muted);\n  font-size:9.5px; letter-spacing:0.18em; text-transform:uppercase;\n}\n.sse-banner .sb-stat .v { color:var(--text); font-weight:500; letter-spacing:0.04em; text-transform:none; }\n.sse-banner .sb-stat .v.warn { color:var(--health-down); }\n.sse-banner .spacer { flex:1; }\n.sse-banner .sb-retry {\n  background:transparent; border:0; border-left:1px solid rgba(255,82,82,0.30);\n  color:var(--health-down); padding:0 16px; height:42px; cursor:pointer;\n  font-family:'JetBrains Mono',monospace; font-size:10px;\n  letter-spacing:0.18em; text-transform:uppercase;\n  display:inline-flex; align-items:center; gap:8px;\n  transition:background 120ms ease;\n}\n.sse-banner .sb-retry:hover { background:rgba(255,82,82,0.12); }\n:root[data-theme=\"light\"] .sse-banner .sb-retry { border-left-color:rgba(196,0,31,0.30); }\n:root[data-theme=\"light\"] .sse-banner .sb-retry:hover { background:rgba(196,0,31,0.10); }\n.sse-banner .sb-ts {\n  display:inline-flex; align-items:center; padding:0 16px;\n  color:var(--muted); font-size:9.5px; letter-spacing:0.18em; text-transform:uppercase;\n  border-left:1px solid rgba(255,82,82,0.30);\n}\n:root[data-theme=\"light\"] .sse-banner .sb-ts { border-left-color:rgba(196,0,31,0.30); }\n\n/* SSE OFF degradation */\nbody[data-sse=\"off\"] .agent-card { opacity:0.6; }\nbody[data-sse=\"off\"] .agent-card .wifi-off { display:inline-flex; }\nbody[data-sse=\"off\"] .kanban-wrap { opacity:0.7; }\nbody[data-sse=\"off\"] .heartbeat-dot { background:var(--health-down) !important; box-shadow:0 0 5px var(--health-down) !important; animation:none !important; }\nbody[data-sse=\"off\"] .h-clock .live { background:var(--health-down) !important; box-shadow:0 0 4px var(--health-down) !important; animation:none !important; opacity:0.55 !important; }\nbody[data-sse=\"off\"] .kpi-bars .b.f-running { background:var(--status-offline) !important; box-shadow:none !important; opacity:0.55; }\nbody[data-sse=\"off\"] .kpi-sys-badge { color:var(--health-down) !important; }\nbody[data-sse=\"off\"] .kpi-sys-badge::before { background:var(--health-down) !important; box-shadow:0 0 8px var(--health-down) !important; }\nbody[data-sse=\"off\"] .agent-card[data-state=\"running\"] { animation:none; }\nbody[data-sse=\"off\"] .agent-card[data-state=\"running\"] .status-bar .sdot,\nbody[data-sse=\"off\"] .agent-card[data-state=\"blocked\"] .status-bar .sdot { animation:none; }\nbody[data-sse=\"off\"] .footer .sb-fastapi .v { color:var(--health-down) !important; }\n\n/* ============ LOADING SCAN ============ */\n.scan-host { position:relative; }\n.scan { position:absolute; inset:0; pointer-events:none; overflow:hidden; z-index:3; display:none; }\nbody[data-load=\"on\"] .scan { display:block; }\n.scan::before {\n  content:\"\"; position:absolute; left:6%; right:6%; height:1px;\n  background:linear-gradient(90deg, transparent 0%, var(--accent) 20%, var(--accent) 80%, transparent 100%);\n  box-shadow:0 0 10px var(--accent), 0 0 20px rgba(0,240,255,0.40);\n  opacity:0;\n  animation:scan-y 1.6s ease-in-out infinite;\n}\n@keyframes scan-y {\n  0%   { top:-1%; opacity:0; }\n  18%  { opacity:0.85; }\n  82%  { opacity:0.85; }\n  100% { top:101%; opacity:0; }\n}\n/* While loading, dim contents but keep frame visible */\nbody[data-load=\"on\"] .agent-card .card-body { opacity:0.18; pointer-events:none; transition:opacity 200ms ease; }\nbody[data-load=\"on\"] .kpi-tile > *:not(.scan):not(.kpi-skel) { opacity:0.16; transition:opacity 200ms ease; }\nbody[data-load=\"on\"] .kcol-body { opacity:0.20; }\nbody[data-load=\"on\"] .agent-card .card-skel { display:flex; }\nbody[data-load=\"on\"] .kpi-tile .kpi-skel { display:flex; }\nbody[data-load=\"on\"] .kcol .kcol-skel { display:flex; }\n.card-skel, .kpi-skel, .kcol-skel {\n  display:none;\n  position:absolute; inset:0; z-index:4;\n  flex-direction:column; align-items:flex-start; justify-content:flex-end;\n  padding:12px 14px; pointer-events:none;\n  font-family:'JetBrains Mono',monospace; font-size:9.5px;\n  letter-spacing:0.22em; text-transform:uppercase;\n  color:var(--accent); opacity:0.85;\n}\n.card-skel .lbl, .kpi-skel .lbl, .kcol-skel .lbl { display:inline-flex; gap:6px; align-items:center; }\n.card-skel .lbl::before, .kpi-skel .lbl::before, .kcol-skel .lbl::before { content:\"▸\"; }\n.card-skel .ph { color:var(--muted); opacity:0.55; font-size:9px; letter-spacing:0.14em; margin-top:3px; }\n.kcol-skel { padding:14px; align-items:center; justify-content:center; }\n\n/* ============ HEADER ============ */\n.header {\n  display:flex; align-items:stretch; gap:0;\n  border:1px solid var(--border);\n  background:linear-gradient(180deg, var(--panel), transparent 140%);\n  font-family:'JetBrains Mono',monospace; font-size:11px;\n}\n.h-brand { display:flex; align-items:center; gap:12px; padding:12px 18px; border-right:1px solid var(--border); }\n.brand-glyph {\n  display:inline-flex; align-items:center; justify-content:center;\n  width:28px; height:28px; border:1px solid var(--accent-border); color:var(--accent);\n  font-size:12px; font-weight:700; letter-spacing:-0.04em; position:relative;\n}\n.brand-glyph::before {\n  content:\"\"; position:absolute; inset:-4px;\n  border-top:1px solid var(--accent-border); border-bottom:1px solid var(--accent-border);\n}\n.brand-stack { display:flex; flex-direction:column; gap:2px; line-height:1.1; }\n.brand-title { font-weight:700; color:var(--text); letter-spacing:0.06em; text-transform:uppercase; font-size:13px; }\n.brand-sub { color:var(--muted); letter-spacing:0.16em; text-transform:uppercase; font-size:9px; }\n\n.h-meta { flex:1; display:flex; align-items:center; padding:0 12px; min-width:0; overflow:hidden; }\n.h-meta .item { display:flex; align-items:center; gap:8px; padding:0 14px; height:100%; color:var(--muted); }\n.h-meta .item .k { color:var(--muted); opacity:0.55; letter-spacing:0.14em; text-transform:uppercase; font-size:9.5px; }\n.h-meta .item .v { color:var(--text); }\n.h-meta .item .v.ok { color:var(--status-done); }\n.h-meta .item.uplink .v::before { content:\"◆\"; color:var(--status-done); margin-right:5px; }\nbody[data-sse=\"off\"] .h-meta .item.uplink .v::before { content:\"✕\"; color:var(--health-down); }\nbody[data-sse=\"off\"] .h-meta .item.uplink .v { color:var(--health-down); }\n.h-meta .sep { width:1px; align-self:stretch; background:var(--border); opacity:0.7; }\n\n.h-right { display:flex; align-items:stretch; border-left:1px solid var(--border); }\n.h-cmd, .h-icon, .theme-toggle button {\n  background:transparent; border:0; color:var(--muted);\n  padding:0 14px; height:100%; cursor:pointer;\n  font-family:'JetBrains Mono',monospace; font-size:10px; letter-spacing:0.14em;\n  text-transform:uppercase;\n  display:inline-flex; align-items:center; gap:8px;\n  transition:color 120ms ease, background 120ms ease;\n}\n.h-cmd { border-right:1px solid var(--border); }\n.h-cmd:hover, .h-icon:hover { color:var(--accent); background:var(--accent-subtle); }\n.h-cmd .kbd {\n  border:1px solid var(--border); padding:2px 5px; font-size:9px;\n  color:var(--text); background:var(--bg); letter-spacing:0;\n}\n.h-clock { display:inline-flex; align-items:center; gap:8px; padding:0 14px; color:var(--text); border-right:1px solid var(--border); }\n.h-clock .live { width:6px; height:6px; border-radius:50%; background:var(--accent); box-shadow:0 0 6px var(--accent); animation:pulse-soft 2.2s ease-in-out infinite; }\n.theme-toggle { display:inline-flex; border-right:1px solid var(--border); }\n.theme-toggle button { padding:0 10px; }\n.theme-toggle button[aria-pressed=\"true\"] { color:var(--bg); background:var(--accent); }\n:root[data-theme=\"light\"] .theme-toggle button[aria-pressed=\"true\"] { color:#f4f6f9; }\n.h-icon { border-right:1px solid var(--border); }\n.h-icon:last-child { border-right:0; }\n\n/* ============ FILTER BAR ============ */\n.filterbar {\n  display:flex; align-items:stretch; gap:0;\n  border:1px solid var(--border); background:var(--panel);\n  font-family:'JetBrains Mono',monospace; font-size:11px;\n}\n.fb-label {\n  display:flex; align-items:center; gap:8px; padding:0 16px; color:var(--muted);\n  font-size:9px; letter-spacing:0.2em; text-transform:uppercase;\n  border-right:1px solid var(--border);\n}\n.fb-label .num { color:var(--accent); border:1px solid var(--accent-border); padding:1px 6px; }\n.fb-search { display:flex; align-items:center; gap:10px; padding:0 14px; flex:1; min-width:220px; max-width:340px; border-right:1px solid var(--border); position:relative; }\n.fb-search::before { content:\"/\"; color:var(--accent); opacity:0.7; font-weight:600; }\n.fb-search input { flex:1; background:transparent; border:0; outline:0; color:var(--text); padding:11px 0; font-family:'JetBrains Mono',monospace; font-size:11.5px; }\n.fb-search input::placeholder { color:var(--muted); opacity:0.6; letter-spacing:0.08em; text-transform:uppercase; font-size:10px; }\n.fb-search .kbd { font-size:9px; padding:2px 5px; border:1px solid var(--border); color:var(--muted); }\n.fb-drops { display:flex; align-items:stretch; flex:1; }\n.fb-drop {\n  background:transparent; border:0; border-right:1px solid var(--border);\n  display:flex; align-items:center; gap:10px;\n  padding:0 16px; cursor:pointer; color:var(--muted);\n  font-family:'JetBrains Mono',monospace; font-size:11px;\n  transition:color 120ms ease, background 120ms ease;\n}\n.fb-drop:hover { color:var(--text); background:var(--accent-subtle); }\n.fb-drop .dk { font-size:9px; letter-spacing:0.2em; text-transform:uppercase; color:var(--muted); opacity:0.7; }\n.fb-drop .dv { color:var(--text); font-size:11px; }\n.fb-drop .caret { color:var(--muted); opacity:0.6; font-size:8px; }\n.fb-clear {\n  background:transparent; border:0; border-left:1px solid var(--border);\n  color:var(--muted); padding:0 16px; cursor:pointer;\n  font-family:'JetBrains Mono',monospace; font-size:10px; letter-spacing:0.14em;\n  text-transform:uppercase; transition:color 120ms ease;\n}\n.fb-clear[disabled] { opacity:0.35; cursor:default; }\n\n/* ============ KPI STRIP ============ */\n.kpi-strip { display:grid; grid-template-columns: 1.4fr 1fr 1fr 1fr 1.6fr; gap:12px; }\n.kpi-tile {\n  position:relative;\n  background:var(--panel); border:1px solid var(--border);\n  padding:14px 16px 12px;\n  display:flex; flex-direction:column; gap:6px; min-height:96px;\n  transition:border-color 160ms ease;\n}\n.kpi-tile:hover { border-color:var(--accent-border); }\n.kpi-head { display:flex; align-items:center; justify-content:space-between;\n  font-family:'JetBrains Mono',monospace; font-size:9px;\n  letter-spacing:0.2em; text-transform:uppercase; color:var(--muted); }\n.kpi-head .tag { color:var(--accent); }\n.kpi-num {\n  font-family:'JetBrains Mono',monospace; font-weight:600;\n  font-size:34px; line-height:1; color:var(--text);\n  letter-spacing:-0.02em; font-variant-numeric:tabular-nums;\n  display:inline-flex; align-items:baseline; gap:8px;\n}\n.kpi-num .total { font-size:18px; color:var(--muted); font-weight:400; }\n.kpi-num .unit  { font-size:13px; color:var(--muted); font-weight:400; letter-spacing:0.04em; }\n.kpi-tile[data-state=\"alert\"] .kpi-num { color:var(--status-blocked); }\n.kpi-tile[data-state=\"ok\"]    .kpi-num { color:var(--accent); text-shadow:0 0 12px rgba(0,240,255,0.25); }\n.kpi-sub { font-family:'JetBrains Mono',monospace; font-size:10px; color:var(--muted); letter-spacing:0.08em; }\n.kpi-sub .warn { color:var(--status-blocked); }\n.kpi-bars { display:flex; gap:3px; margin-top:4px; height:7px; }\n.kpi-bars .b { flex:1; background:var(--border-subtle); }\n.kpi-bars .b.f-running { background:var(--status-running); box-shadow:0 0 6px rgba(0,240,255,0.45); }\n.kpi-bars .b.f-blocked { background:var(--status-blocked); box-shadow:0 0 6px rgba(255,107,53,0.35); }\n.kpi-bars .b.f-done    { background:var(--status-done); }\n.kpi-bars .b.f-idle    { background:var(--status-idle); opacity:0.5; }\n.kpi-bars .b.f-offline { background:var(--status-offline); }\n.kpi-sys { display:grid; grid-template-columns:auto 1px 1fr; gap:14px; align-items:stretch; }\n.kpi-sys .divider { background:var(--border); opacity:0.7; }\n.kpi-sys-left { display:flex; flex-direction:column; justify-content:space-between; gap:4px; }\n.kpi-sys-badge {\n  display:inline-flex; align-items:center; gap:8px;\n  font-family:'JetBrains Mono',monospace; font-size:16px; font-weight:700;\n  letter-spacing:0.18em; color:var(--status-done);\n}\n.kpi-sys-badge::before { content:\"\"; width:9px; height:9px; border-radius:50%; background:var(--status-done); box-shadow:0 0 8px var(--status-done); }\n.kpi-sys-right { display:grid; grid-template-rows:repeat(3,1fr); gap:6px; font-family:'JetBrains Mono',monospace; font-size:10px; }\n.kpi-sys-right .row { display:flex; justify-content:space-between; align-items:baseline; gap:8px; }\n.kpi-sys-right .k { color:var(--muted); letter-spacing:0.16em; text-transform:uppercase; font-size:9px; }\n.kpi-sys-right .v { color:var(--text); font-weight:500; }\n.kpi-sys-right .v.ok { color:var(--status-done); }\n\n/* ============ SECTION LABEL ============ */\n.section-label {\n  display:flex; align-items:center; gap:14px;\n  font-family:'JetBrains Mono',monospace;\n  font-size:10px; letter-spacing:0.2em; text-transform:uppercase; color:var(--muted);\n  padding-top:4px;\n}\n.section-label .num-tag { color:var(--accent); border:1px solid var(--accent-border); padding:2px 8px; }\n.section-label .rule { flex:1; height:1px; background:var(--border); }\n.section-label .endcap { color:var(--muted); opacity:0.7; }\n\n/* ============ CARDS GRID ============ */\n.grid { display:grid; grid-template-columns:repeat(3, minmax(0,1fr)); gap:14px; }\n@media (max-width:1180px) { .grid { grid-template-columns:repeat(2, minmax(0,1fr)); } }\n\n.agent-card {\n  position:relative; background:var(--card);\n  border:1px solid var(--border); box-shadow:var(--glow-card);\n  display:grid; grid-template-columns:4px 1fr;\n  transition:border-color 160ms ease, box-shadow 220ms ease, opacity 220ms ease;\n  cursor:pointer; border-radius:6px; overflow:hidden;\n  min-height:172px;\n}\n.agent-card:hover { border-color:var(--accent-border); box-shadow:var(--glow-hover); }\n.agent-card[data-state=\"running\"] {\n  border-color:rgba(0,240,255,0.35);\n  box-shadow:0 0 0 1px rgba(0,240,255,0.05), 0 0 14px rgba(0,240,255,0.10);\n  animation:card-breathe 4.2s ease-in-out infinite;\n}\n.agent-card[data-state=\"blocked\"] { border-color:rgba(255,107,53,0.32); box-shadow:0 0 12px rgba(255,107,53,0.10); }\n.agent-card[data-state=\"offline\"] { opacity:0.55; }\n\n.rail { position:relative; }\n.agent-card[data-state=\"running\"] .rail { background:var(--status-running); box-shadow:0 0 8px rgba(0,240,255,0.45); }\n.agent-card[data-state=\"idle\"]    .rail { background:var(--status-idle); opacity:0.35; }\n.agent-card[data-state=\"blocked\"] .rail { background:var(--status-blocked); box-shadow:0 0 8px rgba(255,107,53,0.45); }\n.agent-card[data-state=\"done\"]    .rail { background:var(--status-done); box-shadow:0 0 6px rgba(100,255,218,0.40); }\n.agent-card[data-state=\"offline\"] .rail { background:var(--status-offline); }\n\n.card-body { padding:12px 14px 11px; display:flex; flex-direction:column; gap:9px; min-width:0; }\n.card-head { display:flex; align-items:flex-start; gap:11px; }\n.avatar {\n  width:34px; height:34px; flex:none;\n  display:flex; align-items:center; justify-content:center;\n  background:var(--bg); border:1px solid var(--border); color:var(--text);\n  font-family:'JetBrains Mono',monospace; font-weight:700; font-size:12px;\n  position:relative;\n}\n.avatar::before, .avatar::after { content:\"\"; position:absolute; width:4px; height:4px; border-color:var(--accent-border); }\n.avatar::before { top:-1px; left:-1px; border-top:1px solid; border-left:1px solid; }\n.avatar::after  { bottom:-1px; right:-1px; border-bottom:1px solid; border-right:1px solid; }\n.head-text { flex:1; min-width:0; display:flex; flex-direction:column; gap:2px; }\n.head-toprow { display:flex; align-items:center; gap:8px; flex-wrap:wrap; }\n.agent-name { font-family:'Geist',sans-serif; font-weight:600; font-size:13px; color:var(--text); letter-spacing:-0.005em; display:inline-flex; align-items:center; gap:7px; }\n.wifi-off {\n  display:none; align-items:center; color:var(--muted); opacity:0.85;\n}\n.wifi-off svg { width:12px; height:12px; stroke:currentColor; fill:none; stroke-width:1.6; }\n.agent-slug { font-family:'JetBrains Mono',monospace; color:var(--muted); font-size:10.5px; }\n.agent-slug::before { content:\"//\"; opacity:0.5; margin-right:4px; }\n.agent-role { font-family:'Geist',sans-serif; color:var(--muted); font-size:11px; line-height:1.35; }\n.status-bar {\n  display:inline-flex; align-items:center; gap:7px; align-self:flex-start;\n  font-family:'JetBrains Mono',monospace; font-size:9.5px; letter-spacing:0.14em; text-transform:uppercase;\n  padding:3px 7px; border:1px solid var(--border); color:var(--muted);\n}\n.status-bar .sdot { width:6px; height:6px; border-radius:50%; background:var(--status-idle); flex:none; }\n.agent-card[data-state=\"running\"] .status-bar { color:var(--accent); border-color:var(--accent-border); background:var(--accent-subtle); }\n.agent-card[data-state=\"running\"] .status-bar .sdot { background:var(--accent); box-shadow:0 0 6px var(--accent); animation:dot-pulse 1.6s ease-in-out infinite; }\n.agent-card[data-state=\"blocked\"] .status-bar { color:var(--status-blocked); border-color:rgba(255,107,53,0.30); }\n.agent-card[data-state=\"blocked\"] .status-bar .sdot { background:var(--status-blocked); animation:dot-blink 1.1s steps(2) infinite; }\n.agent-card[data-state=\"done\"]    .status-bar { color:var(--status-done); border-color:rgba(100,255,218,0.30); }\n.agent-card[data-state=\"done\"]    .status-bar .sdot { background:var(--status-done); }\n.agent-card[data-state=\"offline\"] .status-bar { color:var(--status-offline); }\n.agent-card[data-state=\"offline\"] .status-bar .sdot { background:var(--status-offline); }\n\n.meta-strip {\n  display:flex; align-items:center; flex-wrap:wrap; gap:4px 10px;\n  font-family:'JetBrains Mono',monospace; font-size:10px; color:var(--muted);\n  border-top:1px solid var(--border-subtle); border-bottom:1px solid var(--border-subtle);\n  padding:6px 0;\n}\n.meta-strip .m-key { font-size:8.5px; letter-spacing:0.18em; text-transform:uppercase; color:var(--muted); opacity:0.55; margin-right:4px; }\n.meta-strip .m-val { color:var(--text); }\n.pane {\n  position:relative;\n  background:linear-gradient(180deg, rgba(0,240,255,0.025), rgba(0,240,255,0) 60%), var(--bg);\n  border:1px solid var(--border-subtle);\n  font-family:'JetBrains Mono',monospace; font-size:10.5px; line-height:1.55;\n  color:var(--text); padding:7px 10px 9px;\n  height:54px; overflow:hidden;\n  -webkit-mask-image:linear-gradient(180deg,#000 0,#000 70%,transparent 100%);\n          mask-image:linear-gradient(180deg,#000 0,#000 70%,transparent 100%);\n  white-space:pre-line;\n}\n.pane .prompt { color:var(--accent); }\n.agent-card[data-state=\"blocked\"] .pane .prompt { color:var(--status-blocked); }\n.agent-card[data-state=\"done\"] .pane .prompt { color:var(--status-done); }\n.pane .dim { color:var(--muted); }\n.pane .hi { color:var(--accent); }\n.pane .ok { color:var(--status-done); }\n.pane .warn { color:var(--status-blocked); }\n\n.card-foot {\n  display:flex; align-items:center; justify-content:space-between;\n  font-family:'JetBrains Mono',monospace; font-size:9px; letter-spacing:0.12em; text-transform:uppercase;\n  color:var(--muted); opacity:0.85;\n}\n.card-foot .lseen-val { color:var(--text); font-weight:500; text-transform:none; letter-spacing:0; }\n.agent-card[data-state=\"running\"] .lseen-val { color:var(--accent); }\n\n/* ============ KANBAN ============ */\n.kanban-wrap {\n  position:relative;\n  background:var(--panel); border:1px solid var(--border);\n  font-family:'JetBrains Mono',monospace;\n}\n.kanban-topline {\n  display:flex; align-items:center; justify-content:space-between;\n  padding:9px 16px; border-bottom:1px solid var(--border);\n  font-size:10px; letter-spacing:0.16em; text-transform:uppercase; color:var(--muted);\n}\n.kanban-topline .lead { display:inline-flex; align-items:center; gap:12px; }\n.kanban-topline .num-tag { color:var(--accent); border:1px solid var(--accent-border); padding:2px 8px; letter-spacing:0.2em; }\n.kanban-topline .live { color:var(--accent); }\n.kanban-topline .live::before { content:\"●\"; margin-right:6px; color:var(--accent); text-shadow:0 0 6px var(--accent); font-size:8px; }\nbody[data-sse=\"off\"] .kanban-topline .live { color:var(--health-down); }\nbody[data-sse=\"off\"] .kanban-topline .live::before { color:var(--health-down); text-shadow:none; content:\"○\"; }\n.kanban-topline .right { display:inline-flex; gap:18px; }\n.kanban-topline .right .it .k { opacity:0.55; margin-right:6px; }\n.kanban-topline .right .it .v { color:var(--text); }\n.kanban-topline .right .it .v.cy { color:var(--accent); }\n\n.kanban-cols { display:grid; grid-template-columns:repeat(5, minmax(0,1fr)); position:relative; }\n.kcol { border-right:1px solid var(--border); position:relative; min-height:200px; outline:none; }\n.kcol:last-child { border-right:0; }\n.kcol-head {\n  display:flex; align-items:center; justify-content:space-between;\n  padding:10px 14px; border-bottom:1px solid var(--border-subtle);\n}\n.kcol-head .name { display:inline-flex; align-items:center; gap:8px; color:var(--text); font-size:10.5px; letter-spacing:0.18em; font-weight:600; }\n.kcol-head .dot { width:7px; height:7px; border-radius:50%; flex:none; }\n.kcol[data-col=\"queue\"]    .kcol-head .dot { background:var(--status-idle); }\n.kcol[data-col=\"running\"]  .kcol-head .dot { background:var(--accent); box-shadow:0 0 6px var(--accent); animation:dot-pulse 1.6s ease-in-out infinite; }\n.kcol[data-col=\"blocked\"]  .kcol-head .dot { background:var(--status-blocked); box-shadow:0 0 6px var(--status-blocked); }\n.kcol[data-col=\"review\"]   .kcol-head .dot { background:var(--status-blocked); }\n.kcol[data-col=\"done\"]     .kcol-head .dot { background:var(--status-done); }\n.kcol-head .cnt { color:var(--muted); font-size:9.5px; letter-spacing:0.16em; }\n.kcol-head .cnt .num { color:var(--text); }\n.kcol-body { padding:6px 0; max-height:340px; overflow:auto; }\n.kcol-body::-webkit-scrollbar { width:4px; }\n.kcol-body::-webkit-scrollbar-thumb { background:var(--accent-border); }\n\n.krow {\n  display:grid; grid-template-columns:48px 60px minmax(0,1fr) 44px 8px;\n  align-items:center; gap:8px; padding:6px 12px;\n  font-size:10.5px; line-height:1.3; color:var(--text);\n  cursor:pointer; outline:none;\n  border-top:1px solid transparent; border-bottom:1px solid transparent;\n}\n.krow:hover { background:var(--accent-subtle); }\n.krow .sdot { width:6px; height:6px; border-radius:50%; flex:none; justify-self:start; }\n.krow[data-st=\"queue\"] .sdot { background:var(--status-idle); }\n.krow[data-st=\"running\"] .sdot { background:var(--accent); box-shadow:0 0 4px var(--accent); animation:dot-pulse 1.6s ease-in-out infinite; }\n.krow[data-st=\"blocked\"] .sdot { background:var(--status-blocked); animation:dot-blink 1.1s steps(2) infinite; }\n.krow[data-st=\"review\"] .sdot { background:var(--status-blocked); }\n.krow[data-st=\"done\"] .sdot { background:var(--status-done); }\n.krow .id { color:var(--text); font-size:10.5px; font-weight:500; }\n.krow[data-st=\"running\"] .id { color:var(--accent); text-shadow:0 0 5px rgba(0,240,255,0.45); }\n.krow[data-st=\"blocked\"] .id, .krow[data-st=\"review\"] .id { color:var(--status-blocked); }\n.krow[data-st=\"done\"] .id { color:var(--status-done); }\n.krow .owner { color:var(--muted); font-size:9.5px; letter-spacing:0.08em; text-transform:uppercase; min-width:0; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; }\n.krow .time { color:var(--muted); font-size:9.5px; text-align:right; opacity:0.75; }\n.krow .caret { color:var(--muted); opacity:0.6; font-size:9px; justify-self:end; }\n.krow:hover .caret { color:var(--accent); opacity:1; }\n\n.kcol-empty {\n  padding:30px 16px; color:var(--muted); font-size:9.5px; letter-spacing:0.18em; text-transform:uppercase;\n  display:flex; flex-direction:column; align-items:flex-start; gap:6px; opacity:0.7;\n}\n.kcol-empty::before { content:\"▸ AGUARDANDO O PRIMEIRO EVENTO\"; color:var(--accent); opacity:0.85; }\n.kcol-empty .hint { font-size:9px; letter-spacing:0.14em; color:var(--muted); opacity:0.55; }\n\n/* ============ FOOTER ============ */\n.footer {\n  display:flex; align-items:stretch; gap:0;\n  border:1px solid var(--border); background:var(--panel);\n  font-family:'JetBrains Mono',monospace; font-size:10px;\n  color:var(--muted); letter-spacing:0.12em; text-transform:uppercase;\n  margin-top:auto;\n  position:sticky; bottom:12px;\n  box-shadow:0 -4px 18px rgba(0,0,0,0.35);\n  z-index:6;\n  flex-wrap:wrap;\n}\n:root[data-theme=\"light\"] .footer { box-shadow:0 -2px 12px rgba(10,22,40,0.08); }\n.footer .grp { display:inline-flex; align-items:center; gap:0; }\n.footer .sb-item { display:inline-flex; align-items:center; gap:6px; padding:8px 13px; }\n.footer .sb-item .k { color:var(--muted); opacity:0.55; font-size:9px; letter-spacing:0.16em; }\n.footer .sb-item .v { color:var(--text); }\n.footer .sb-item .v.ok { color:var(--status-done); }\n.footer .sb-item .v.warn { color:var(--status-blocked); }\n.footer .sb-item .v.cy { color:var(--accent); }\n.footer .sb-item .v.danger { color:var(--health-down); }\n.footer .sep { width:1px; align-self:stretch; background:var(--border); opacity:0.7; }\n.footer .heartbeat-dot {\n  width:6px; height:6px; border-radius:50%; background:var(--status-done);\n  box-shadow:0 0 5px var(--status-done);\n  animation:heartbeat 1.2s ease-in-out infinite;\n}\n.footer .spacer { flex:1; }\n\n/* DEMO TOGGLE strip in footer */\n.demo-strip {\n  display:inline-flex; align-items:stretch;\n  border-left:1px solid var(--border);\n  font-family:'JetBrains Mono',monospace;\n}\n.demo-strip .dlabel {\n  display:inline-flex; align-items:center; gap:8px;\n  padding:0 14px; color:var(--muted); font-size:9px; letter-spacing:0.2em; text-transform:uppercase;\n  border-right:1px solid var(--border);\n}\n.demo-strip .dlabel::before { content:\"▸\"; color:var(--accent); }\n.demo-btn {\n  background:transparent; border:0; border-right:1px solid var(--border);\n  padding:0 12px; height:34px; color:var(--muted); cursor:pointer;\n  font-family:'JetBrains Mono',monospace; font-size:9.5px; letter-spacing:0.16em; text-transform:uppercase;\n  display:inline-flex; align-items:center; gap:7px;\n  transition:color 120ms ease, background 120ms ease;\n}\n.demo-btn .dd { width:6px; height:6px; border-radius:50%; flex:none; background:var(--muted); opacity:0.5; }\n.demo-btn:hover { color:var(--text); background:var(--accent-subtle); }\n.demo-btn[aria-pressed=\"true\"] { color:var(--accent); background:var(--accent-subtle); }\n.demo-btn[aria-pressed=\"true\"] .dd { background:var(--accent); box-shadow:0 0 4px var(--accent); opacity:1; }\n.demo-btn[data-mode=\"sse-off\"][aria-pressed=\"true\"] { color:var(--health-down); background:rgba(255,82,82,0.08); }\n.demo-btn[data-mode=\"sse-off\"][aria-pressed=\"true\"] .dd { background:var(--health-down); box-shadow:0 0 4px var(--health-down); }\n:root[data-theme=\"light\"] .demo-btn[data-mode=\"sse-off\"][aria-pressed=\"true\"] { background:rgba(196,0,31,0.10); }\n.demo-fire {\n  background:transparent; border:0; border-right:1px solid var(--border);\n  padding:0 12px; height:34px; color:var(--muted); cursor:pointer;\n  font-family:'JetBrains Mono',monospace; font-size:9.5px; letter-spacing:0.16em; text-transform:uppercase;\n  display:inline-flex; align-items:center; gap:7px;\n  transition:color 120ms ease;\n}\n.demo-fire:hover { color:var(--accent); background:var(--accent-subtle); }\n.demo-fire::before { content:\"●\"; font-size:8px; color:var(--status-done); }\n.demo-prm { padding:0 14px; display:inline-flex; align-items:center; gap:8px; color:var(--muted); font-size:9.5px; letter-spacing:0.14em; text-transform:uppercase; border-right:1px solid var(--border); }\n.demo-prm .v { color:var(--text); }\n.demo-prm .v.on { color:var(--accent); }\n\n/* ============ TOAST ============ */\n.toast-stack {\n  position:fixed; bottom:78px; right:20px; z-index:90;\n  display:flex; flex-direction:column-reverse; gap:8px;\n  pointer-events:none; max-width:320px;\n}\n.toast {\n  pointer-events:auto;\n  display:flex; align-items:center; gap:12px;\n  min-width:280px;\n  background:var(--panel); border:1px solid var(--border);\n  padding:10px 14px;\n  font-family:'JetBrains Mono',monospace; font-size:10.5px;\n  letter-spacing:0.14em; text-transform:uppercase;\n  color:var(--text);\n  box-shadow:0 6px 18px rgba(0,0,0,0.4);\n  animation:toast-in 220ms cubic-bezier(.2,.7,.2,1) both;\n  cursor:pointer;\n  position:relative;\n}\n:root[data-theme=\"light\"] .toast { box-shadow:0 4px 14px rgba(10,22,40,0.14); }\n.toast[data-out=\"true\"] { animation:toast-out 200ms ease both; }\n.toast .tdot { width:7px; height:7px; border-radius:50%; flex:none; }\n.toast[data-kind=\"success\"] { border-left:2px solid var(--status-done); }\n.toast[data-kind=\"success\"] .tdot { background:var(--status-done); box-shadow:0 0 5px var(--status-done); }\n.toast[data-kind=\"info\"] { border-left:2px solid var(--accent); }\n.toast[data-kind=\"info\"] .tdot { background:var(--accent); box-shadow:0 0 5px var(--accent); }\n.toast[data-kind=\"warn\"] { border-left:2px solid var(--status-blocked); }\n.toast[data-kind=\"warn\"] .tdot { background:var(--status-blocked); }\n.toast .tmsg { flex:1; }\n.toast .tsub { color:var(--muted); font-size:9px; letter-spacing:0.18em; }\n.toast .ttime { color:var(--muted); font-size:9px; letter-spacing:0.14em; opacity:0.85; }\n.toast .tx {\n  position:absolute; top:4px; right:4px;\n  background:transparent; border:0; color:var(--muted);\n  font-family:'JetBrains Mono',monospace; font-size:9px; cursor:pointer;\n  padding:2px 5px; opacity:0; transition:opacity 120ms ease;\n}\n.toast:hover .tx { opacity:0.7; }\n.toast:hover .tx:hover { opacity:1; color:var(--text); }\n@keyframes toast-in { from { opacity:0; transform:translateX(24px); } to { opacity:1; transform:none; } }\n@keyframes toast-out { from { opacity:1; transform:none; } to { opacity:0; transform:translateX(24px); } }\n\n/* ============ ANIMATIONS ============ */\n@keyframes pulse-soft { 0%,100% { opacity:0.65; box-shadow:0 0 4px var(--accent); } 50% { opacity:1; box-shadow:0 0 9px var(--accent); } }\n@keyframes dot-pulse { 0%,100% { box-shadow:0 0 4px var(--accent); transform:scale(1); } 50% { box-shadow:0 0 10px var(--accent), 0 0 16px rgba(0,240,255,0.35); transform:scale(1.18); } }\n@keyframes dot-blink { 0%,49% { opacity:1; } 50%,100% { opacity:0.35; } }\n@keyframes card-breathe { 0%,100% { box-shadow:0 0 0 1px rgba(0,240,255,0.05), 0 0 14px rgba(0,240,255,0.08); } 50% { box-shadow:0 0 0 1px rgba(0,240,255,0.10), 0 0 22px rgba(0,240,255,0.18); } }\n@keyframes heartbeat { 0%,80%,100% { opacity:1; } 40% { opacity:0.3; } }\n@keyframes icon-blink { 0%,55% { opacity:1; } 60%,100% { opacity:0.45; } }\n\n/* ============ prefers-reduced-motion — honored ============ */\n@media (prefers-reduced-motion: reduce) {\n  *, *::before, *::after {\n    animation-duration:0.01ms !important;\n    animation-iteration-count:1 !important;\n    transition-duration:0.01ms !important;\n    scroll-behavior:auto !important;\n  }\n  /* Replace running dot pulse with static elevated opacity */\n  .h-clock .live,\n  .status-bar .sdot,\n  .kcol-head .dot,\n  .krow .sdot,\n  .heartbeat-dot { opacity:0.85 !important; transform:none !important; }\n  /* Replace scan-line with static cyan dot + label */\n  .scan::before { display:none !important; }\n  .scan::after {\n    content:\"▸ CONNECTING\";\n    position:absolute; top:50%; left:50%; transform:translate(-50%,-50%);\n    color:var(--accent); font-family:'JetBrains Mono',monospace;\n    font-size:10px; letter-spacing:0.22em;\n  }\n  /* SSE banner uses fade only */\n  .sse-banner { transition:opacity 0.01ms !important; top:-64px !important; opacity:0; }\n  .sse-banner[data-on=\"true\"] { top:0 !important; opacity:1; }\n  body[data-sse=\"off\"] .viewport { padding-top:62px; transition:none !important; }\n  /* Toast fade */\n  .toast { animation:none !important; opacity:1; transform:none; }\n  .toast[data-out=\"true\"] { opacity:0; transform:none; }\n  /* Card breathe off */\n  .agent-card[data-state=\"running\"] { animation:none !important; }\n}\n\n/* prefers-contrast: more — fortify */\n@media (prefers-contrast: more) {\n  :root[data-theme=\"dark\"]  { --border:#2e5f8a; --border-subtle:#244f74; --muted:#7eb4cf; }\n  :root[data-theme=\"light\"] { --border:#8e9aaa; --border-subtle:#a4afbf; --muted:#3f4a5c; }\n  *:focus-visible { outline-width:2px !important; }\n}";
const cockpitScript = "/* ============ THEME ============ */\n(function(){\n  const KEY='cockpit-theme';\n  const saved = localStorage.getItem(KEY);\n  if (saved==='light' || saved==='dark') document.documentElement.setAttribute('data-theme', saved);\n  const buttons = document.querySelectorAll('.theme-toggle button');\n  function sync() {\n    const cur = document.documentElement.getAttribute('data-theme') || 'dark';\n    buttons.forEach(b => b.setAttribute('aria-pressed', b.dataset.themeSet === cur ? 'true' : 'false'));\n  }\n  buttons.forEach(b => b.addEventListener('click', () => {\n    document.documentElement.setAttribute('data-theme', b.dataset.themeSet);\n    localStorage.setItem(KEY, b.dataset.themeSet); sync();\n  }));\n  sync();\n})();\n\n/* ============ CLOCK ============ */\n(function(){\n  const el = document.getElementById('clock');\n  const ts = document.getElementById('sseTs');\n  const sync = document.getElementById('sysSync');\n  const pad = n => String(n).padStart(2,'0');\n  function tick() {\n    const d = new Date();\n    const stamp = `T+ ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;\n    el.textContent = stamp;\n    if (document.body.dataset.sse === 'on') {\n      sync.textContent = `${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())} -03:00`;\n    }\n  } tick(); setInterval(tick, 1000);\n})();\n\n/* ============ AGENTS DATA ============ */\nconst AGENTS = [\n  { slug:'pavan',    name:'José Pavan',       role:'Consigliere',                model:'opus-4.7',   cli:'cc',    status:'running', task:'RN-2180', last:'há 45s',\n    initials:'JP',\n    pane:`<span class=\"prompt\">›</span> <span class=\"dim\">cc.dev</span> handoff <span class=\"hi\">pavan→daniel</span> <span class=\"dim\">--phase 2</span>\\n<span class=\"dim\">› assembling context bundle · 14 files · 2.1k tokens</span>\\n<span class=\"dim\">›</span> <span class=\"ok\">bundle ready</span>` },\n  { slug:'daniel',   name:'Daniel Singh',     role:'Dev sênior — líder de área', model:'opus-4.7',   cli:'cc',    status:'running', task:'RN-2182', last:'há 12s',\n    initials:'DS',\n    pane:`<span class=\"prompt\">$</span> <span class=\"dim\">cc.dev</span> refactor <span class=\"hi\">connection-per-call</span>\\n<span class=\"dim\">› patching</span> services/runner/queue.py <span class=\"dim\">· 14 hunks staged</span>\\n<span class=\"dim\">›</span> <span class=\"ok\">✓ smoke test</span>` },\n  { slug:'lucas',    name:'Lucas Marchetti',  role:'Diretor de marketing',       model:'sonnet-4.6', cli:'cc',    status:'blocked', task:'RN-2177', last:'há 30min',\n    initials:'LM',\n    pane:`<span class=\"prompt\">›</span> <span class=\"warn\">awaiting human</span> · approve copy post Instagram?\\n<span class=\"prompt\">›</span> <span class=\"dim\">draft em</span> memory/2026-05-09-post.md\\n<span class=\"dim\">› elapsed 30:14 since prompt</span>` },\n  { slug:'vinicius', name:'Vinicius Zanella', role:'Especialista — lojistas',    model:'haiku-4.5',  cli:'cc',    status:'idle',    task:null,      last:'há 2h',\n    initials:'VZ',\n    pane:`<span class=\"dim\">›</span> <span class=\"dim\">STANDBY · conversation compacted at 14:22</span>\\n<span class=\"dim\">› context flushed · 18.2k → 1.4k tokens</span>\\n<span class=\"dim\">› watching inbox/lojistas/</span>` },\n  { slug:'felipe',   name:'Felipe Conti',     role:'Especialista — comercial',   model:'opus-4.7',   cli:'codex', status:'done',    task:'DN-2169', last:'há 10min',\n    initials:'FC',\n    pane:`<span class=\"prompt\">✓</span> <span class=\"ok\">complete</span> · campanha pré-aprovação\\n<span class=\"dim\">› 14 lojistas notified · template v3 · 100% delivery</span>\\n<span class=\"dim\">› artifact pushed → DN-2169 closed</span>` },\n  { slug:'barsi',    name:'Luiz Barsi',       role:'CFO read-only',              model:'haiku-4.5',  cli:'cc',    status:'offline', task:null,      last:'há 2h20',\n    initials:'LB',\n    pane:`<span class=\"dim\">› NO HEARTBEAT · daemon unreachable</span>\\n<span class=\"dim\">› last seen 2026-05-10 12:02:14 -03:00</span>\\n<span class=\"dim\">› vps.cockpit / agents/barsi · pid 8421 SIGTERM</span>` },\n];\nconst STATE_LABEL = { running:'RUNNING', idle:'IDLE', blocked:'BLOCKED', done:'DONE', offline:'OFFLINE' };\nconst PANE_LABEL  = { running:'STDOUT // PANE.001', idle:'STDOUT // idle', blocked:'STDIN // AWAIT.HUMAN', done:'STDOUT // EXIT.0', offline:'STDOUT // OFFLINE' };\n\nfunction renderCards() {\n  const wifiSvg = `<svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.6\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"1\" y1=\"1\" x2=\"23\" y2=\"23\"/><path d=\"M16.72 11.06A10.94 10.94 0 0 1 19 12.55\"/><path d=\"M5 12.55a10.94 10.94 0 0 1 5.17-2.39\"/><path d=\"M10.71 5.05A16 16 0 0 1 22.58 9\"/><path d=\"M1.42 9a15.91 15.91 0 0 1 4.7-2.88\"/><path d=\"M8.53 16.11a6 6 0 0 1 6.95 0\"/><line x1=\"12\" y1=\"20\" x2=\"12.01\" y2=\"20\"/></svg>`;\n  const container = document.getElementById('cards');\n  container.innerHTML = AGENTS.map((a,i) => `\n    <article class=\"agent-card scan-host\" data-state=\"${a.status}\" data-slug=\"${a.slug}\" tabindex=\"0\" role=\"listitem\"\n             aria-label=\"Agent ${a.name}, ${STATE_LABEL[a.status]}${a.task ? ', task ' + a.task : ''}\">\n      <div class=\"scan\" aria-hidden=\"true\"></div>\n      <div class=\"card-skel\"><span class=\"lbl\">CONNECTING</span><span class=\"ph\">▸ no data // fetching</span></div>\n      <div class=\"rail\" aria-hidden=\"true\"></div>\n      <div class=\"card-body\">\n        <div class=\"card-head\">\n          <div class=\"avatar\" aria-hidden=\"true\">${a.initials}</div>\n          <div class=\"head-text\">\n            <div class=\"head-toprow\">\n              <span class=\"agent-name\">${a.name}<span class=\"wifi-off\" title=\"SSE disconnected\" aria-hidden=\"true\">${wifiSvg}</span></span>\n            </div>\n            <span class=\"agent-slug\">${a.slug}</span>\n            <span class=\"agent-role\">${a.role}</span>\n          </div>\n          <span class=\"status-bar\" aria-hidden=\"true\"><span class=\"sdot\"></span>${STATE_LABEL[a.status]}</span>\n        </div>\n        <div class=\"meta-strip\" aria-hidden=\"true\">\n          <span><span class=\"m-key\">MDL</span><span class=\"m-val\">${a.model}</span></span>\n          <span><span class=\"m-key\">CLI</span><span class=\"m-val\">${a.cli}</span></span>\n          <span><span class=\"m-key\">TASK</span><span class=\"m-val\">${a.task || '—'}</span></span>\n        </div>\n        <div class=\"pane\">\n          <div style=\"opacity:0.55;font-size:9px;letter-spacing:0.18em;text-transform:uppercase;margin-bottom:3px\">${PANE_LABEL[a.status]}</div>\n          ${a.pane}\n        </div>\n        <div class=\"card-foot\">\n          <span>LAST·SEEN <span class=\"lseen-val\">${a.last}</span></span>\n          <span>${a.cli.toUpperCase()} · ${a.model}</span>\n        </div>\n      </div>\n    </article>\n  `).join('');\n\n  // Card click -> open (mock: toast)\n  container.querySelectorAll('.agent-card').forEach(card => {\n    card.addEventListener('click', () => {\n      fireToast({ kind:'info', msg:`AGENT · ${card.dataset.slug.toUpperCase()}`, sub:'OPEN MODAL · MOCK' });\n    });\n    card.addEventListener('keydown', e => {\n      if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); card.click(); }\n    });\n  });\n}\nrenderCards();\n\n/* ============ KANBAN DATA ============ */\nconst KCOLS = [\n  { id:'queue',   name:'QUEUE',   rows:[\n    { id:'RN-2185', owner:'pavan',    time:'+12s', st:'queue' },\n    { id:'RN-2184', owner:'daniel',   time:'+38s', st:'queue' },\n    { id:'RN-2183', owner:'lucas',    time:'+1m',  st:'queue' },\n    { id:'DN-2170', owner:'felipe',   time:'+2m',  st:'queue' },\n  ]},\n  { id:'running', name:'RUNNING', rows:[\n    { id:'RN-2182', owner:'daniel',   time:'12s',  st:'running' },\n    { id:'RN-2180', owner:'pavan',    time:'45s',  st:'running' },\n    { id:'RN-2181', owner:'daniel',   time:'3m18', st:'running' },\n  ]},\n  { id:'blocked', name:'BLOCKED', rows:[\n    { id:'RN-2177', owner:'lucas',    time:'30m',  st:'blocked' },\n  ]},\n  { id:'review',  name:'REVIEW',  rows:[]},\n  { id:'done',    name:'DONE',    rows:[\n    { id:'DN-2169', owner:'felipe',   time:'10m',  st:'done' },\n    { id:'DN-2168', owner:'felipe',   time:'1h02', st:'done' },\n    { id:'DN-2167', owner:'pavan',    time:'1h44', st:'done' },\n    { id:'RN-2166', owner:'daniel',   time:'2h10', st:'done' },\n  ]},\n];\n\nfunction renderKanban() {\n  const root = document.getElementById('kbcols');\n  root.innerHTML = KCOLS.map(c => `\n    <div class=\"kcol scan-host\" data-col=\"${c.id}\" tabindex=\"0\" role=\"group\" aria-label=\"${c.name} column, ${c.rows.length} tasks\">\n      <div class=\"scan\" aria-hidden=\"true\"></div>\n      <div class=\"kcol-skel\"><span class=\"lbl\">CONNECTING</span></div>\n      <div class=\"kcol-head\">\n        <span class=\"name\"><span class=\"dot\" aria-hidden=\"true\"></span>${c.name}</span>\n        <span class=\"cnt\"><span class=\"num\">${String(c.rows.length).padStart(2,'0')}</span> / ∞</span>\n      </div>\n      <div class=\"kcol-body\">\n        ${c.rows.length === 0\n          ? `<div class=\"kcol-empty\"><span class=\"hint\">// review · queue desde 03:14</span></div>`\n          : c.rows.map(r => `\n              <div class=\"krow\" data-st=\"${r.st}\" tabindex=\"0\" role=\"button\" aria-label=\"Task ${r.id}, owner ${r.owner}, ${r.time}\">\n                <span class=\"sdot\" aria-hidden=\"true\"></span>\n                <span class=\"id mono\">${r.id}</span>\n                <span class=\"owner mono\">@${r.owner}</span>\n                <span class=\"time mono\">${r.time}</span>\n                <span class=\"caret\" aria-hidden=\"true\">›</span>\n              </div>\n            `).join('')\n        }\n      </div>\n    </div>\n  `).join('');\n\n  root.querySelectorAll('.krow').forEach(row => {\n    row.addEventListener('click', () => {\n      const id = row.querySelector('.id').textContent;\n      fireToast({ kind:'info', msg:`TASK · ${id}`, sub:'OPEN DETAIL · MOCK' });\n    });\n    row.addEventListener('keydown', e => {\n      if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); row.click(); }\n    });\n  });\n}\nrenderKanban();\n\n/* ============ DEMO MODE — central state machine ============ */\nconst body = document.body;\nconst sseBanner = document.getElementById('sseBanner');\nconst sseAttempt = document.getElementById('sseAttempt');\nconst ssePing = document.getElementById('ssePing');\nconst sseBackoff = document.getElementById('sseBackoff');\nconst sysBadge = document.getElementById('sysBadge');\nconst sysSub = document.getElementById('sysSub');\nconst sysHb = document.getElementById('sysHb');\nconst sysRtt = document.getElementById('sysRtt');\nconst fbFastapi = document.getElementById('fbFastapi');\nconst fbHb = document.getElementById('fbHb');\nconst kbLive = document.getElementById('kbLive');\n\nconst demoBtns = document.querySelectorAll('.demo-btn');\nlet currentMode = 'live';\nlet retryTimer = null;\nlet retryCount = 0;\n\nfunction setMode(mode, opts = {}) {\n  if (mode === currentMode && !opts.force) return;\n  // teardown previous\n  if (currentMode === 'sse-off') stopRetryLoop();\n\n  currentMode = mode;\n  demoBtns.forEach(b => b.setAttribute('aria-pressed', b.dataset.mode === mode ? 'true' : 'false'));\n\n  if (mode === 'live') {\n    body.dataset.sse = 'on';\n    body.dataset.load = 'off';\n    sseBanner.setAttribute('data-on','false');\n    sysBadge.textContent = 'OK';\n    sysBadge.style.color = '';\n    sysSub.textContent = 'FASTAPI · SSE · 200';\n    sysHb.textContent = '1.2s';\n    sysRtt.textContent = '24ms';\n    fbFastapi.textContent = '200'; fbFastapi.className = 'v ok';\n    fbHb.textContent = '1.2s';\n    kbLive.textContent = 'LIVE · SSE';\n  } else if (mode === 'loading') {\n    body.dataset.sse = 'on';\n    body.dataset.load = 'on';\n    sseBanner.setAttribute('data-on','false');\n    sysSub.textContent = 'FASTAPI · CONNECTING…';\n    sysBadge.textContent = '••';\n    kbLive.textContent = 'CONNECTING';\n  } else if (mode === 'sse-off') {\n    body.dataset.sse = 'off';\n    body.dataset.load = 'off';\n    sseBanner.setAttribute('data-on','true');\n    sysBadge.textContent = 'DOWN';\n    sysSub.textContent = 'FASTAPI · SSE · DROP';\n    sysHb.textContent = '— —';\n    sysRtt.textContent = '— —';\n    fbFastapi.textContent = 'DROP'; fbFastapi.className = 'v danger';\n    fbHb.textContent = '— —';\n    kbLive.textContent = 'STALE · 2m14s';\n    retryCount = 3;\n    startRetryLoop();\n  }\n}\n\nfunction startRetryLoop() {\n  let pingMs = 134;\n  function tick() {\n    retryCount++;\n    sseAttempt.textContent = `tentativa ${String(retryCount).padStart(2,'0')} / ∞`;\n    pingMs += 1;\n    const m = Math.floor(pingMs/60), s = pingMs % 60;\n    ssePing.textContent = `-${m}m${String(s).padStart(2,'0')}s`;\n    const backoff = Math.min(2 ** (retryCount-2), 60);\n    sseBackoff.textContent = `${backoff.toFixed(1)}s`;\n  }\n  tick();\n  retryTimer = setInterval(tick, 4000);\n}\nfunction stopRetryLoop() {\n  if (retryTimer) { clearInterval(retryTimer); retryTimer = null; }\n}\n\ndemoBtns.forEach(b => b.addEventListener('click', () => {\n  const wasMode = currentMode;\n  const nextMode = b.dataset.mode;\n  setMode(nextMode);\n  // If transitioning FROM sse-off TO live, fire reconnect toast\n  if (wasMode === 'sse-off' && nextMode === 'live') {\n    fireToast({ kind:'success', msg:'● SSE RECONECTADO', sub:'PING 24MS · 200', ttl:4200 });\n  }\n  // If entering loading, after ~2s auto-return to live\n  if (nextMode === 'loading') {\n    setTimeout(() => { if (currentMode === 'loading') setMode('live'); }, 2400);\n  }\n}));\n\n/* SSE banner retry button */\ndocument.getElementById('sseRetry').addEventListener('click', () => {\n  retryCount++;\n  sseAttempt.textContent = `tentativa ${String(retryCount).padStart(2,'0')} / ∞`;\n  fireToast({ kind:'warn', msg:'▸ RETRY DISPARADO', sub:`tentativa ${retryCount}`, ttl:2400 });\n});\n\n/* ============ TOAST ============ */\nconst toastRoot = document.getElementById('toasts');\nfunction fireToast({ kind='info', msg='', sub='', ttl=3800 } = {}) {\n  const pad = n => String(n).padStart(2,'0');\n  const d = new Date();\n  const t = document.createElement('div');\n  t.className = 'toast';\n  t.setAttribute('data-kind', kind);\n  t.setAttribute('role','status');\n  t.innerHTML = `\n    <span class=\"tdot\" aria-hidden=\"true\"></span>\n    <div class=\"tmsg\">\n      <div>${msg}</div>\n      ${sub ? `<div class=\"tsub\">${sub}</div>` : ''}\n    </div>\n    <span class=\"ttime\">${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}</span>\n    <button type=\"button\" class=\"tx\" aria-label=\"Dismiss toast\">✕</button>\n  `;\n  toastRoot.appendChild(t);\n  const dismiss = () => {\n    t.setAttribute('data-out','true');\n    setTimeout(() => t.remove(), 220);\n  };\n  t.querySelector('.tx').addEventListener('click', (e) => { e.stopPropagation(); dismiss(); });\n  t.addEventListener('click', dismiss);\n  setTimeout(dismiss, ttl);\n}\n\ndocument.getElementById('fireToast').addEventListener('click', () => {\n  fireToast({ kind:'success', msg:'● SSE RECONECTADO', sub:'PING 24MS · 200', ttl:4000 });\n});\n\n/* ============ ESC closes things ============ */\ndocument.addEventListener('keydown', e => {\n  if (e.key === 'Escape') {\n    // Dismiss top toast if any\n    const top = toastRoot.querySelector('.toast:last-child');\n    if (top) { top.setAttribute('data-out','true'); setTimeout(() => top.remove(), 220); }\n  }\n});\n\n/* ============ prefers-reduced-motion indicator ============ */\n(function(){\n  const mq = window.matchMedia('(prefers-reduced-motion: reduce)');\n  const flag = document.getElementById('prmFlag');\n  function sync() {\n    flag.textContent = mq.matches ? 'ON · honored' : 'off';\n    flag.className = 'v' + (mq.matches ? ' on' : '');\n  }\n  sync();\n  if (mq.addEventListener) mq.addEventListener('change', sync);\n  else mq.addListener(sync);\n})();\n\n/* ============ Focus the search on `/` ============ */\ndocument.addEventListener('keydown', e => {\n  if (e.key === '/' && document.activeElement.tagName !== 'INPUT') {\n    e.preventDefault();\n    document.getElementById('fbSearch').focus();\n  }\n});\n\n/* ============ Boot demo: brief loading -> live ============ */\nsetMode('loading', { force:true });\nsetTimeout(() => setMode('live'), 1800);";

